using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API.
/// HttpClient and ILogger are injected via constructor DI —
/// they do NOT appear in the tool schema exposed to LLMs.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a post by its ID from the REST API.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post (1-100)")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {PostId}", postId);
        var json = await httpClient.GetStringAsync($"/posts/{postId}", cancellationToken);
        return json;
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts to this user ID (omit for all posts)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        logger.LogInformation("Listing posts from {Url}", url);
        var json = await httpClient.GetStringAsync(url, cancellationToken);
        return json;
    }

    [McpServerTool, Description("Get all comments for a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to retrieve comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching comments for post {PostId}", postId);
        var json = await httpClient.GetStringAsync($"/posts/{postId}/comments", cancellationToken);
        return json;
    }

    [McpServerTool(Destructive = false, ReadOnly = true),
     Description("Search posts by title substring (case-insensitive).")]
    public async Task<string> SearchPosts(
        [Description("Text to search for in post titles")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching posts for '{Query}'", query);
        var json = await httpClient.GetStringAsync("/posts", cancellationToken);
        var posts = JsonSerializer.Deserialize<JsonElement[]>(json) ?? [];

        var matches = posts
            .Where(p => p.GetProperty("title").GetString()!
                .Contains(query, StringComparison.OrdinalIgnoreCase))
            .ToArray();

        return JsonSerializer.Serialize(matches, JsonOptions);
    }
}

